package com.example;

import org.eclipse.jface.preference.IPreferenceStore;

class JavaPlugin {
    public static JavaPlugin getDefault() { return new JavaPlugin(); }
    public IPreferenceStore getPreferenceStore() { return null; } // Dummy
}

interface IExtensionStateModel {
    boolean getBooleanProperty(String key);
    void setBooleanProperty(String key, boolean value);
}

interface IMemento {
    Boolean getBoolean(String key);
}

public class JavaNavigatorViewActionProvider {
    private static final String TAG_LIBRARIES_NODE= "org.eclipse.jdt.internal.ui.navigator.librariesnode";
    private IExtensionStateModel fStateModel;

    public void restoreState(IMemento memento) {
        Boolean showLibrariesNodeState= null;
        if (memento != null) {
            showLibrariesNodeState= memento.getBoolean(TAG_LIBRARIES_NODE);
        }

        // If no memento try to restore from preference store
        if (showLibrariesNodeState == null) {
            IPreferenceStore store= JavaPlugin.getDefault().getPreferenceStore();
            boolean isDefault = store.getString(TAG_LIBRARIES_NODE).equals(IPreferenceStore.STRING_DEFAULT_DEFAULT);
            boolean storedBoolean = store.getBoolean((TAG_LIBRARIES_NODE));
            showLibrariesNodeState= new Boolean(isDefault || storedBoolean);
        }
    }
}

